const fs = require('fs');
let html = fs.readFileSync('index.html','utf8');
const idx = html.indexOf('const NYC_DATA');
const arrStart = html.indexOf('[', idx);
let depth=0, arrEnd=arrStart;
for(let j=arrStart;j<html.length;j++){
  if(html[j]==='[') depth++;
  if(html[j]===']'){ depth--; if(depth===0){ arrEnd=j+1; break; } }
}
const arr = JSON.parse(html.substring(arrStart, arrEnd));
console.log('Loaded', arr.length, 'NYC spots');

// All researched fixes from 4 batches
const fixes = [
  // BATCH 1
  {id:1112,description:"The undisputed king of Trinidadian doubles in NYC, this tiny Bed-Stuy counter serves some of the most addictive $2 snacks in the five boroughs. The bara is perfectly fried, the channa filling is warmly spiced, and the pepper sauce will make you rethink every bland lunch you have ever had. Cash-only, no-frills, and absolutely essential.",instagram:"",website:"",dishes:["Doubles","Bake and Shark","Aloo Pie"]},
  {id:1127,description:"This no-frills Chinatown joint specializes in Henan province cooking and draws lines for good reason. The hand-pulled noodles are the main event, but the big tray chicken is a shareable showstopper that could feed a small army. The fluorescent lighting hides some of the most soulful regional Chinese food in Manhattan.",dishes:["Big Tray Chicken","Hand-Pulled Noodles with Lamb","Spicy Cumin Lamb Burger"]},
  {id:1129,description:"A legit trompo-spinning taqueria in East Harlem turning out some of the best al pastor tacos north of Puebla. The vertical spit of marinated pork is shaved to order, and the resulting tacos topped with pineapple, cilantro, and onion are the real deal. Fast, cheap, and honest Mexican street food.",neighborhood:"East Harlem",dishes:["Tacos Al Pastor","Mulitas","Quesadilla de Chicharron"]},
  {id:1132,description:"Named after Singapore famous hawker center, this FiDi spot brings the breadth of Southeast Asian street food to lower Manhattan. The laksa and Hainanese chicken rice are respectable renditions for homesick Singaporeans and curious New Yorkers alike. A rare find in a neighborhood otherwise dominated by sad salad chains.",instagram:"laupasatnyc",website:"https://www.laupasatnyc.com",dishes:["Hainanese Chicken Rice","Laksa","Char Kway Teow"]},
  {id:1139,description:"A fluorescent-lit Midtown lunch counter slinging Cuban-Latin comfort food to office workers since 1970. The cubano sandwich is a heavyweight contender for best in the city, and the daily steam-table specials -- pernil, oxtail, rice and beans -- hit like a home-cooked meal. Loud, cramped, cash-only, and perfect.",dishes:["Cubano Sandwich","Pernil Plate","Oxtail with Rice and Beans"]},
  {id:1143,description:"An Upper East Side institution since 1972 serving one of the most iconic burgers in New York -- a no-nonsense, perfectly griddled patty on a sesame bun that has kept preppy regulars coming back for decades. The cottage fries are non-negotiable, and the Bloody Marys are stiff enough to recalibrate your weekend. Old-school charm with zero interest in trends.",dishes:["Cheeseburger","Cottage Fries","Bloody Mary"]},
  {id:1145,description:"A white-tablecloth Roman Italian restaurant on the Upper East Side that feels like a neighborhood secret the regulars would prefer you not know about. Chef Sandro Fioriti cooks with the confidence of someone who has been making fresh pasta since before you were born. The cacio e pepe is textbook, and the daily specials always reward the adventurous.",instagram:"sandrosnyc",website:"https://www.sandrosnyc.com",dishes:["Cacio e Pepe","Branzino","Burrata with Prosciutto"]},
  {id:1156,description:"A reliable East Village Thai spot feeding the neighborhood affordable, flavorful curries and noodles for years. The pad Thai is solid but the real move is the drunken noodles or a fiery green curry. It will not change your life, but at these prices in this neighborhood, it does not need to.",website:"https://www.spicethaikitchen.com",dishes:["Drunken Noodles","Green Curry","Pad Thai"]},
  {id:1157,description:"A 1929 Flatiron luncheonette that feels like stepping through a time portal to old New York -- formica counters, hand-written checks, and egg creams made the way God intended. The tuna melt is legendary, and the matzo ball soup could cure what ails you. The kind of place that makes you furious at every modern fast-casual concept.",instagram:"eisenbergsnyc",website:"https://www.eisenbergsnyc.com",dishes:["Tuna Melt","Matzo Ball Soup","Egg Cream"]},
  {id:1109,description:"A Jackson Heights staple dishing out hearty Pakistani and South Asian fare that keeps the neighborhood large desi community well-fed and happy. The lamb karahi is a must, cooked down in a wok until the spices meld into something transcendent. BYOB-friendly, enormous portions, and a bill that makes you wonder why you ever eat anywhere in Manhattan.",dishes:["Lamb Karahi","Chicken Biryani","Seekh Kebab"]},
  {id:1579,description:"A beloved Nolita dive bar with a neon shark on the wall and a crowd that ranges from neighborhood old-timers to off-duty service industry folks. The drinks are cold and fairly priced, the jukebox is solid, and nobody is trying to impress anyone. The ideal bar for when you just want to be a person drinking a beer.",instagram:"springloungenyc",dishes:["Cold Beer","Shot and a Beer","Bloody Mary"]},
  {id:1126,description:"A 24-hour Hell Kitchen institution stuffing every conceivable filling into fried or baked dough pockets, with a menu so long it reads like a novel. Whether you want classic beef, wild boar, or a sweet plantain dessert empanada at 3 AM, Empanada Mama has you covered. Loud, colorful, cash-friendly, and exactly the kind of place you need after a night out.",instagram:"empanadamama",dishes:["Beef Empanada","Chicken Avocado Empanada","Sweet Plantain Empanada"]},
  {id:1121,description:"A sprawling Midtown sports bar near Penn Station and MSG that serves as a reliable pregame or postgame destination for every Rangers, Knicks, and concert crowd. The food is standard pub fare -- burgers, wings, nachos -- but it is really about the dozens of screens and the cold beer. Nothing fancy, and it knows it.",instagram:"mustangharrys",dishes:["Burger","Buffalo Wings","Nachos"]},
  {id:1123,description:"One of New York most storied jazz venues, Birdland has kept the spirit of bebop alive in Midtown West since 1949. The current room on 44th Street books top-tier talent nightly, from big bands to trios, and the sound is always impeccable. Yes, there is a cover and a drink minimum, but you are paying for living musical history.",instagram:"birdlandjazz",dishes:["Craft Cocktails","Birdland Burger","Live Jazz Set"]},
  {id:1125,description:"The Blue Note in Greenwich Village is one of the world most iconic jazz clubs, a bucket-list venue that has hosted virtually every major name in jazz since 1981. The intimate room puts you close enough to see the sweat on the musicians brows, and the late-night sets are where the real magic happens. Pricey, but an evening here is quintessential New York.",instagram:"bluenotenyc",dishes:["Signature Cocktails","Late Night Set","Weekend Brunch with Live Jazz"]},
  {id:1117,description:"An East Village Italian pastry shop going strong since 1894, making it one of the oldest in the city. The cannoli are shatteringly crisp, the cheesecake is dense and creamy in the old-school Italian style, and the display cases look like edible baroque art. Skip the trendy bakery du jour and come here for pastry your great-grandparents would recognize.",instagram:"venieros",dishes:["Cannoli","Italian Cheesecake","Sfogliatella"]},
  {id:1138,description:"A tiny Midtown West ramen shop famous for its rich, golden chicken paitan broth that rivals any tonkotsu in the city. The signature chicken ramen is silky, deeply flavored, and practically demands you slurp every last drop. Expect a line -- the place only seats about 20 -- but the wait is a badge of honor among NYC ramen obsessives.",dishes:["Chicken Paitan Ramen","Spicy Chicken Ramen","Chicken Chashu"]},
  {id:1144,description:"Located inside the Neue Galerie on Museum Mile, Cafe Sabarsky is a meticulous recreation of a Viennese coffeehouse, right down to the Klimt on the walls and the waiters in vests. The sachertorte and strudel are exquisite, the coffee is properly Viennese, and the atmosphere makes you forget you are on the Upper East Side. Reservations strongly recommended.",instagram:"neuegalerie",website:"https://www.neuegalerie.org/cafes/sabarsky",dishes:["Sachertorte","Apple Strudel","Wiener Schnitzel"]},
  {id:1147,description:"The self-proclaimed Sturgeon King has been smoking and slicing fish on the Upper West Side since 1908. The sturgeon is buttery and mild, the nova is silky perfection, and the scrambled eggs with lox and onions might be the greatest breakfast dish in New York. Come hungry, come early, and bring cash.",instagram:"barneygreengrass",dishes:["Sturgeon Platter","Scrambled Eggs with Nova and Onions","Bagel with Lox"]},
  {id:1148,description:"More than a deli, Zabars is an Upper West Side institution and a shrine to the art of Jewish-New York food shopping. The smoked fish counter is world-class, the babka is transcendent, and the upstairs housewares department has outfitted more NYC kitchens than IKEA ever will. If you do not leave with at least three things you did not plan to buy, you were not paying attention.",instagram:"zabars",dishes:["Nova Lox","Babka","Rugelach"]},
  {id:1149,description:"Michael Psilakis beloved Upper West Side Greek restaurant serves rustic, homestyle Hellenic cooking that is generous in both portion and spirit. The braised lamb is fall-off-the-bone magnificent, the spreads are vibrant, and the whole experience feels like dinner at a very talented Greek grandmother house. One of the best value restaurants on the UWS.",instagram:"kefirestaurant",dishes:["Braised Lamb Shank","Mezze Spreads","Pastitsio"]},
  {id:1150,description:"A newcomer to the East Village bringing refined Caribbean cooking to a neighborhood always hungry for something different. The menu draws from across the islands with thoughtful, elevated preparations that treat Caribbean cuisine with the fine-dining respect it deserves. Creative cocktails and a warm, inviting atmosphere round out a genuinely exciting experience.",dishes:["Jerk Chicken","Oxtail","Rum Punch"]},
  {id:1151,description:"A Mexican steakhouse concept in Midtown marrying prime cuts with bold Mexican flavors, chiles, and salsas in a way that feels both inventive and authentic. The bone marrow with tortillas is an instant classic starter, and the steaks come with accompaniments that make a standard American steakhouse seem one-dimensional.",dishes:["Bone Marrow Tacos","Ribeye with Salsa Macha","Elote"]},
  {id:1152,description:"A mezcal-forward Mexican cocktail bar in the East Village serving creative drinks alongside shareable Mexican snacks. The mezcal selection is deep and well-curated, the cocktails are inventive without being gimmicky, and the late-night vibe is exactly right. A great spot for when you want something more interesting than another tequila soda.",dishes:["Mezcal Cocktails","Tacos","Guacamole"]},
  {id:1153,description:"Founded by a former headwaiter from Peter Luger, Wolfgang delivers massive dry-aged porterhouses in a grand Midtown setting with soaring ceilings and old-school swagger. The meat is impeccably sourced and aged in-house, and the creamed spinach is one of the best steakhouse sides in the city. Pricey and unapologetic about it -- this is serious steak for serious eaters.",dishes:["Porterhouse for Two","Dry-Aged Ribeye","Creamed Spinach"]},
  {id:1154,description:"A Midtown East steakhouse institution since 1977 that has fed generations of power-lunchers, expense-account diners, and tourists who want the quintessential New York steak experience. The USDA Prime cuts are expertly prepared, the wine list is encyclopedic, and the green-painted exterior is as iconic as the restaurant itself. Classic to the core.",dishes:["USDA Prime Dry-Aged Ribeye","Lobster Tail","Colorado Lamb Chops"]},
  {id:1155,description:"The sit-down restaurant extension of the legendary 1914 appetizing shop, located on Orchard Street in the LES. Everything the original counter does brilliantly -- smoked fish, bagels, latkes, egg creams -- gets the full-service treatment here with table service and a cocktail menu. The Super Heebster alone justifies crossing any borough.",dishes:["Super Heebster","Classic Board with Smoked Fish","Latkes with Applesauce"]},

  // BATCH 2
  {id:1158,description:"This legendary Italian sandwich shop has been quietly destroying every other sandwich in Manhattan since 1986. The bread is fresh, the imported meats and cheeses are impeccable, and the combinations are dialed in after decades of practice. Cash only, no seating, zero frills -- just perfect sandwiches that justify every minute of the line.",instagram:"alidoronyc",dishes:["Chris Colombo","Alidoro Special","Michelangelo"]},
  {id:1159,description:"A gorgeous French-Vietnamese spot on the Lower East Side from chef Ha Luu that treats both culinary traditions with serious respect. The menu dances between banh mi-inspired bites and French technique with Vietnamese ingredients, and the results are stunning. Fusion done right is not a dirty word -- it is a revelation.",instagram:"hasdacbiet",website:"https://www.hasdacbiet.com",dishes:["Bo Luc Lac","Banh Xeo","Pate Chaud"]},
  {id:1161,description:"Detroit-style pizza done with serious conviction -- thick, crispy-edged squares with cheese that caramelizes against the pan in the most beautiful way. The Emmy Burger is a sleeper hit that rivals dedicated burger joints across the city. Williamsburg location is the OG, and it still packs in crowds who know that square pizza is the superior format.",dishes:["The Emmy","Emmy Burger","Colony Pizza"]},
  {id:1163,description:"Brooklyn answer to the great American deli sandwich, and honestly one of the best delis in the entire city. They cure their own meats, source obsessively, and stack sandwiches with the kind of care that makes you feel personally looked after. The rotating specials are always worth ordering.",dishes:["The Hero","Pastrami Sandwich","Turkey and Cranberry"]},
  {id:1164,description:"A vibrant Caribbean-inspired bar and restaurant in the East Village that brings island flavors with real finesse and fantastic cocktails. The jerk-spiced dishes hit hard, the rum program is deep, and the whole vibe feels like a permanent vacation from the grim reality of winter in New York.",instagram:"barkabawa",dishes:["Jerk Chicken","Oxtail","Rum Punch"]},
  {id:1169,description:"The Wythe Hotel French brasserie from the Frenchette team that makes Williamsburg feel like the Left Bank. Rotisserie chicken, beautiful seafood platters, and one of the best burger-frites combos in the city -- all served in a gorgeous high-ceilinged room. Effortlessly cool in the way only Brooklyn restaurants backed by serious talent can pull off.",dishes:["Rotisserie Chicken","Le Croc Burger","Plateau de Fruits de Mer"]},
  {id:1179,description:"A chic SoHo French spot that channels a Parisian neighborhood bistro with polished execution New York demands. The menu leans into French classics done with restraint and quality ingredients -- think well-executed steak frites and lovely crudo. A grown-up room that does not take itself too seriously.",instagram:"cesarnewyork",website:"https://www.cesarnewyork.com",dishes:["Steak Frites","Escargots","Creme Brulee"]},
  {id:1185,description:"Daniel Boulud slightly more casual Upper East Side jewel that remains one of the best French restaurants in the city, full stop. The four-muse menu concept gives the kitchen room to flex, and the execution is consistently flawless. Where the UES crowd goes when they want exceptional food without the full Michelin formality of Daniel.",dishes:["Pate en Croute","Duck Confit","Seasonal Tasting Menu"]},
  {id:1192,description:"A more accessible sibling to the omakase temple Sushi Noz, offering stunning Japanese cuisine in Chelsea without requiring a second mortgage. The quality of fish is extraordinary -- the Noz team sources impeccably -- and the format lets you explore a wider range of Japanese dishes beyond pure sushi. Still not cheap, but the value-to-quality ratio is remarkable.",dishes:["Omakase Sushi Selection","Wagyu Tataki","Uni Toast"]},
  {id:1196,description:"An elevated Korean dining experience in the Flatiron area that treats Korean cuisine with the reverence and refinement it deserves. The banchan spreads are beautiful, the proteins are prepared with serious technique, and the cocktail program incorporates Korean flavors seamlessly. Korean food for a special occasion.",dishes:["Galbi","Kimchi Jjigae","Korean Fried Chicken"]},
  {id:1198,description:"A serene West Village omakase counter from chef Yoshihiko Kousaka that is one of the city most underrated high-end sushi experiences. The rice is exceptional -- perfectly seasoned and at the ideal temperature -- and the fish selection reflects decades of expertise. Intimate, quiet, and focused entirely on the craft.",dishes:["Chef Omakase","Toro","Uni Nigiri"]},
  {id:1216,description:"A creative New American spot tucked into Chinatown that draws on the neighborhood multicultural energy for a menu that is inventive and soulful. The space has a cool, slightly moody vibe that matches the food ambition, and the cocktails are thoughtfully composed. Exactly the kind of chef-driven restaurant that makes Chinatown exciting.",dishes:["Roasted Half Chicken","Hand-pulled Noodles","Seasonal Crudo"]},
  {id:1220,description:"A legendary French restaurant on the Upper East Side that was revived after its original 1937 incarnation closed, bringing back old-school French bistro charm with a modern sensibility. The room drips with nostalgia -- red banquettes, brass fixtures -- and the menu delivers faithful renditions of French classics. A love letter to a bygone era of New York dining.",dishes:["Quenelles de Brochet","Coq au Vin","Grand Marnier Souffle"]},
  {id:1231,description:"A red-sauce Italian-American joint in Bushwick that has become one of Brooklyn most beloved neighborhood restaurants. The pasta is made with love, the portions are honest, and the whole experience feels like eating at your coolest friend Italian grandmother house. No pretension, just great food in a fun room.",dishes:["Chicken Parm","Rigatoni Bolognese","Garlic Bread"]},
  {id:1232,description:"A groundbreaking Palestinian restaurant in Brooklyn Heights from chef Ayat Masoud that puts Palestinian cuisine on the fine-dining map with extraordinary grace. The musakhan is transcendent, the hummus is the platonic ideal, and every dish tells a story rooted in tradition but elevated with real technique. Essential eating.",dishes:["Musakhan","Hummus","Lamb Mansaf"]},
  {id:1233,description:"The retail and casual dining arm of the Sushi Noz universe on the Upper East Side, offering pristine Japanese ingredients and prepared foods to take home. The chirashi bowls are gorgeous and the curated selection of Japanese pantry items is unmatched in the city. Your neighborhood Japanese gourmet shop -- if your neighborhood has impeccable taste.",dishes:["Chirashi Bowl","Onigiri","Japanese Bento Box"]},
  {id:1238,description:"Marie-Aude Rose all-day French cafe inside the Roman and Williams Guild showroom in SoHo is as beautiful as you would expect, but the food more than holds its own against the design-magazine setting. The croque madame might be the best in the city, and the pastry program is genuinely world-class. A scene with substance.",dishes:["Croque Madame","Madeleines","Duck Confit"]},
  {id:1239,description:"A tiny West Village seafood spot from chef Ed Szymanski that punches miles above its weight class with an obsessive focus on British and European seafood traditions. The fish and chips elevated to fine-dining quality is a flex, and the Dover sole is immaculate. Getting a reservation is a blood sport, but the payoff is extraordinary.",dishes:["Fish and Chips","Dover Sole","Prawn Toast"]},
  {id:1242,description:"A sleek French brasserie in Rockefeller Center that proves Midtown can have genuinely cool restaurants. The raw bar is stellar, the steak tartare is textbook, and the room makes you feel like a stylish extra in a Wes Anderson film. The rare Midtown spot that locals actually seek out rather than stumble into.",dishes:["Steak Tartare","Plateau de Fruits de Mer","Duck a l Orange"]},
  {id:1254,description:"A stunning Mediterranean restaurant perched on the DUMBO waterfront with jaw-dropping views of the Manhattan Bridge and skyline. The food is actually great, which is borderline miraculous for a restaurant with views this good. Wood-fired dishes, excellent pastas, and a wine list deep on natural and Mediterranean selections.",dishes:["Wood-Fired Branzino","Hand-cut Pasta","Mezze Platter"]},
  {id:1261,description:"The DUMBO outpost of the global Italian restaurant chain, set inside the gorgeous 1 Hotel Brooklyn Bridge with unbeatable waterfront views. The pastas are reliable, the cicchetti are fun for sharing, and eating on that terrace on a summer evening is one of the great pleasures of living in this city. Classic Italian in a setting hard to beat.",dishes:["Cacio e Pepe","Branzino","Burrata"]},
  {id:1266,description:"A sprawling, lavish Chinese restaurant in Midtown West that goes big on Cantonese and Sichuan classics with luxe presentation. The dim sum is a highlight, and the Peking duck is carved tableside with proper ceremony. The kind of grand Chinese dining room that feels like an event -- perfect for large groups and celebrations.",dishes:["Peking Duck","Soup Dumplings","Lobster with Ginger and Scallion"]},
  {id:1270,description:"A refined New American restaurant in Brooklyn Heights that brings real culinary ambition to a neighborhood that desperately needed it. The seasonal menu showcases smart, produce-driven cooking with enough technique to impress without feeling fussy. A go-to for Brooklyn Heights locals who want a proper dinner out without crossing the bridge.",dishes:["Roasted Chicken","Seasonal Crudo","Handmade Pasta"]},
  {id:1273,description:"A fun, lively Mexican spot in Park Slope that brings Korean-Mexican fusion with creative tacos and killer margaritas. The vibe is casual and energetic, perfect for groups, and the menu has enough range to satisfy everyone from the adventurous eater to the kid who just wants a quesadilla. A neighborhood staple for good reason.",dishes:["Korean BBQ Tacos","Bulgogi Burrito","Spicy Margarita"]},
  {id:1293,description:"The only Michelin-starred Mexican restaurant in NYC, and it absolutely earns that star with deeply soulful, traditional Mexican cooking in Long Island City. Chef Cosme Aguilar mole is a masterwork -- complex, layered, and worth the trip alone. The space is modest, the prices are fair, and every dish tastes like it was made by someone who genuinely loves this cuisine.",dishes:["Mole Negro","Tamal de Pollo","Carnitas"]},
  {id:1302,description:"The beating heart of the Bronx Little Italy -- an indoor market stuffed with family-run vendors selling everything from hand-pulled mozzarella to imported olive oil to fresh pasta. This is not a tourist trap; it is where real Italians from the neighborhood still shop. Arthur Avenue makes Manhattan Little Italy look like a theme park.",instagram:"arthuravenue",website:"https://www.arthuravenue.com",neighborhood:"Bronx",dishes:["Fresh Mozzarella","Italian Combo Sandwich","Cannoli"]},
  {id:1303,description:"A Bronx institution on Arthur Avenue serving some of the most genuinely soulful Italian food in all of New York City. Chef Roberto Paciullo runs the room with charismatic energy that makes every table feel like a celebration. The pastas are handmade, the specials are always worth ordering, and the experience is a reminder of what Italian dining should feel like.",instagram:"robertosofarthurave",website:"https://www.robertosofarthurave.com",neighborhood:"Bronx",dishes:["Cavatelli alla Roberto","Burrata","Daily Pasta Special"]},
  {id:1310,description:"A beloved Jackson Heights street food stall turned brick-and-mortar serving some of the crispiest, most flavorful samosas in the city. The fillings rotate and get creative -- think beyond standard potato to pulled pork and other wild combos -- but the classic veggie samosa is still king. Cheap, fast, and exactly the kind of place that makes Jackson Heights the greatest food neighborhood.",dishes:["Classic Veggie Samosa","Chicken Tikka Samosa","Chaat Platter"]},
  {id:1316,description:"The hip Nolita sibling of the legendary Chinatown dim sum parlor, serving a curated menu of dim sum classics and creative cocktails in a sleek, modern space. The original egg rolls and dumplings translate beautifully, and the late-night scene is surprisingly fun. Dim sum for the downtown crowd -- same quality, cooler vibe.",dishes:["Original Egg Roll","Shrimp Rice Roll","Roast Pork Buns"]},

  // BATCH 3
  {id:1337,description:"This tiny Greenpoint taqueria caused an absolute frenzy when it opened, with lines snaking down the block for good reason. The focus is dead simple -- a tight menu of tacos done with precision and soul, using handmade tortillas that put 90% of NYC Mexican spots to shame. The suadero taco alone is worth the wait.",dishes:["Suadero Taco","Campechano Taco","Al Pastor Taco"]},
  {id:1374,description:"The Seaport District crown jewel is this massive rooftop concert venue and hangout space perched above the East River with jaw-dropping Brooklyn Bridge views. More of an events and entertainment destination than a restaurant, hosting big-name concerts in summer and transforming into a winter wonderland in colder months. One of the best open-air spaces in lower Manhattan.",dishes:["Seasonal Cocktails","Concert Series Tickets","Rooftop Bar Bites"]},
  {id:1381,description:"Perched atop The Standard Hotel in the Meatpacking District, Le Bain is the kind of rooftop bar where fashion people, Europeans, and runway models converge. There is a plunge pool on the roof, panoramic Hudson views, and DJs spinning until the early hours. A scene, unapologetically -- dress up, show up late, and embrace the chaos.",instagram:"lebainny",dishes:["Espresso Martini","French 75","Charcuterie Plate"]},
  {id:1403,description:"Hugh Mangum brought serious Texas-style BBQ to the East Village and proved that NYC can absolutely hang in the smoker game. The brisket is the star -- beautifully smoked with a legit bark and buttery interior that rivals what you would find in Austin. Started as a Smorgasburg stall and grew into a mini-empire, but the original still has the most soul.",dishes:["Brisket","Pulled Pork","Burnt Ends"]},
  {id:1409,description:"Jean-Georges Vongerichten vegetable-forward restaurant in the ABC Carpet and Home building proves that plant-based eating can be genuinely luxurious. The space is gorgeous -- all earthy tones, natural light, and wellness energy without being preachy about it. The cooking is inventive and globally inspired, making even committed carnivores forget they are eating vegetables.",dishes:["Roasted Carrot Bowl","Mushroom and Grain Bowl","Kelp Noodle Cacio e Pepe"]},
  {id:1418,description:"The NYC outpost of Shigemi Kawahara legendary Hakata-style ramen chain that has been slinging tonkotsu since 1985. The East Village location still draws crowds for its rich, porky broth and perfectly springy thin noodles. The hirata buns are a must-order starter, and the Akamaru Modern is the bowl that put them on the map here.",dishes:["Akamaru Modern Ramen","Shiromaru Classic Ramen","Pork Buns"]},
  {id:1429,description:"Operating since 1924, Totonno is one of New York true pizza legends -- a no-frills Coney Island institution charring pies in the same coal-fired oven for a century. The pizza is magnificently simple: thin, blistered crust with high-quality mozzarella and a bright tomato sauce. Cash only, limited hours, occasionally closed on a whim -- old New York at its best and most frustrating.",website:"https://www.totonnos.com",dishes:["Fresh Mozzarella Pizza","White Pizza","Margherita"]},
  {id:1434,description:"Downtown Brooklyn sprawling underground food hall packs in around 40 vendors and is a legit destination for serious eating. The anchor tenant is a Katz Deli outpost slinging the same pastrami as the LES original, but the real move is exploring the global lineup. Chaotic, loud, and perfect for groups who can never agree on what to eat.",neighborhood:"Downtown Brooklyn",dishes:["Katz Pastrami Sandwich","Bunsmith Bao Buns","Arepa Lady Corn Cakes"]},
  {id:1437,description:"Maria Piedad Cano started selling arepas from a street cart in Jackson Heights in the 90s and built a devoted following that turned into a brick-and-mortar empire. The arepas de choclo -- sweet corn cakes stuffed with molten cheese -- are absolutely iconic. This is Colombian comfort food at its purest, and Jackson Heights is the only place it feels right eating it.",dishes:["Arepa de Choclo con Queso","Arepa de Carne","Chorizo con Arepa"]},
  {id:1455,description:"America first fine dining restaurant, opened in 1837, still serving steaks in the Financial District to power-lunch brokers and tourists who appreciate a side of history with their porterhouse. The Delmonico steak was literally invented here, and the old-school wood-paneled dining room feels like stepping into a Wall Street time capsule. The gravitas is unmatched.",dishes:["Delmonico Steak","Lobster Newburg","Baked Alaska"]},
  {id:1464,description:"This West Village spot from former Masa chefs takes the hand roll -- temaki -- and elevates it into a full dining experience that is both fun and ridiculously delicious. The nori is always impeccably crispy, the rice is warm, and the fillings range from classic tuna to creative specials. A genuinely unique concept and the counter seating makes for a great date night.",dishes:["Spicy Tuna Hand Roll","Blue Crab Hand Roll","Lobster Hand Roll"]},
  {id:1468,description:"Sitting on the roof of the building adjacent to the Wythe Hotel in Williamsburg, Bar Blondeau is the kind of effortlessly cool rooftop that makes you feel like you are in a French film set in Brooklyn. The Manhattan skyline views are stunning, the wine list is well-curated with a French lean, and the vibe is relaxed enough that you do not feel like you are at a club. Perfect summer sunset spot.",dishes:["French Fries with Aioli","Croque Monsieur","Seasonal Spritzes"]},
  {id:1472,description:"This Williamsburg gem does the impossible -- serves some of the best steak in NYC at prices that will not require a second mortgage. The small, rustic space with its open grill is all about fire-kissed meats, with the butcher steak being one of the best deals in the city. Do not sleep on the grilled vegetables either; the whole carrots off that grill are transcendent.",dishes:["Butcher Steak","Grilled Whole Carrots","Garlic Bread"]},
  {id:1473,description:"Zachary Golper Carroll Gardens bakery is where NYC bread nerds go to worship -- the sourdough is dark, deeply caramelized, and unlike anything else in the city. Bien cuit literally means well done in French, and these loaves take that philosophy to glorious extremes with long fermentations and bold crusts. You are coming here for bread that will ruin you for all other bread.",dishes:["Miche Sourdough","Chocolate Babka","Almond Croissant"]},
  {id:1479,description:"The Italian food emporium that is part market, part restaurant complex, part sensory overload in the best way. The Flatiron flagship is a sprawling temple to Italian gastronomy with multiple restaurants, a rooftop beer garden, and enough imported products to fill a warehouse. Come hungry, come with a plan, or just wander and eat your way through.",dishes:["Fresh Pasta at Il Pastaio","Pizza from La Pizza","Gelato"]},
  {id:1481,description:"Esther Choi Korean ramen fusion spot in Chelsea Market is a tiny, mighty operation that smashes together Korean flavors with ramen technique and makes it all sing. The kimchi ramen and the rice cakes are the move, and everything hits with authentic Korean depth. A quick, casual counter situation -- grab a stool and slurp.",dishes:["Kimchi Ramen","Tteokbokki","Bulgogi Ramen"]},
  {id:1487,description:"Alex Raij and Eder Montero Carroll Gardens spot is a deeply personal love letter to Spanish and Moorish cooking that goes way beyond tapas-bar cliches. The menu digs into the Jewish and Arabic influences on Iberian cuisine, producing dishes that feel both ancient and totally fresh. Cozy, romantic, and perfect for sharing small plates with sherry.",dishes:["Fried Eggplant with Honey","Lamb Meatballs","Stuffed Dates"]},
  {id:1497,description:"Georgian food finally gets its proper NYC moment at this West Village charmer that showcases one of the world most underrated cuisines. Khachapuri -- that glorious cheese-filled bread -- is the star, but the whole menu of dumplings, walnut-laced salads, and grilled meats deserves attention. The natural wine list pairs beautifully with the bold, herbaceous flavors.",dishes:["Adjaruli Khachapuri","Khinkali","Pkhali"]},
  {id:1501,description:"Abdul Elenani Palestinian restaurant has become one of the most celebrated spots in southern Brooklyn, serving soulful, vibrant mezze and grilled meats that tell the story of Palestinian home cooking. The musakhan -- sumac-spiced chicken over taboon bread -- is a revelation, and the hummus is silky perfection. Worth the trek for food this honest and delicious.",neighborhood:"Bay Ridge",dishes:["Musakhan","Hummus","Lamb Kebab Platter"]},
  {id:1504,description:"From the people behind Lilia, Leo brings the same fresh pasta mastery to a more expansive Williamsburg space inside the old Domino Sugar factory. The pizza and pasta are both outstanding -- Italian-American cooking through a fine-dining lens that still manages to feel fun and approachable. Big, buzzy, and the waterfront setting is gorgeous.",dishes:["Mafaldini with Pink Sauce","Pizza Margherita","Soft Serve"]},
  {id:1520,description:"Jean-Georges Vongerichten farm-to-table restaurant inside ABC Carpet and Home was one of the defining restaurants of the 2010s NYC dining scene, championing local and organic ingredients before it was trendy. The space is ethereally beautiful and the cooking is clean, seasonal, and elegant, proving that restraint can be just as exciting as excess.",dishes:["Roasted Carrot and Avocado Salad","Whole Wheat Pizza","Sundae with Salted Caramel"]},
  {id:1522,description:"Jeremiah Stone and Fabian von Hauske LES wine bar is the cooler, more casual sibling to their restaurant Contra -- a place where natural wine flows freely and the small plates are way more ambitious than they need to be for a bar. The menu changes constantly, but everything is executed with precision. This is where chefs eat on their nights off.",dishes:["Beef Tartare","Aged Cheddar with Honey","Grilled Oysters"]},
  {id:1528,description:"The original 1916 Coney Island hot dog stand that spawned an empire and an annual Fourth of July eating contest that has become as American as the hot dogs themselves. The snap of that natural casing dog with mustard and sauerkraut on the boardwalk is a quintessential NYC experience. Come for the nostalgia, the crinkle-cut fries, and the chaos of Coney Island.",dishes:["Original Hot Dog","Crinkle-Cut Fries","Corn Dog"]},
  {id:1537,description:"New York quintessential neighborhood brasserie -- reliable, buzzy, and always packed with a good-looking crowd eating elevated comfort food. The East Village location has great energy without the Midtown corporate feel of some other outposts. The place you go when you want a solid burger, a well-made cocktail, and a lively atmosphere without overthinking it.",dishes:["The Smith Burger","Mac and Cheese","Ricotta Meatballs"]},
  {id:1541,description:"Masahiro Urushido West Village cocktail bar brilliantly bridges Japanese precision with American cocktail culture, creating drinks that are technically flawless and impossibly fun. The highball machine churns out the crispest, most perfectly carbonated whisky highballs in the city. The space has a warm izakaya energy that makes it dangerously easy to stay for three more rounds.",dishes:["Japanese Whisky Highball","Katana Kitten Martini","Curry Popcorn"]},
  {id:1566,description:"This underground Chinatown club is one of NYC grittiest, most no-frills dance spots -- a dark, sweaty basement literally where the music is the point and nothing else matters. It draws a young, adventurous crowd with eclectic DJ bookings spanning techno, house, hip-hop, and everything in between. Do not expect bottle service; do expect to dance until your legs give out.",instagram:"basementny",website:"",dishes:["DJ Sets","Dance Floor","Late-Night Vibes"]},
  {id:1571,description:"Perched atop the modernist James Hotel in SoHo, Jimmy is a rooftop pool bar that feels like a Miami import dropped into lower Manhattan. The outdoor pool, skyline views, and retro-chic design make it one of the more photogenic rooftops in the city. It leans more scene-y than serious, but that is exactly the point -- a place to see and be seen.",dishes:["Frozen Margarita","Spicy Paloma","Bar Snacks"]},
  {id:1573,description:"The rooftop bar at the Wythe Hotel is Williamsburg original cool-kid rooftop, offering unobstructed views of the Manhattan skyline that never get old. The cocktail program is more thoughtful than your average hotel rooftop, and the indoor-outdoor setup means it is actually a year-round destination. Go on a weekday evening for the full magic without the crowd crush.",dishes:["Seasonal Cocktails","Wine by the Glass","Light Bar Snacks"]},
  {id:1610,description:"Sitting atop the Graduate Roosevelt Island hotel, the Panorama Room offers genuinely jaw-dropping 360-degree views that most NYC rooftops can only dream about -- the East Side skyline, the Queensboro Bridge, and both rivers. The tram ride over is half the fun. The cocktails are tropical-leaning and well-executed, making this one of the city most underrated rooftop experiences.",neighborhood:"Roosevelt Island",dishes:["Tropical Cocktails","Frozen Drinks","Bar Bites"]},
  {id:1614,description:"This Williamsburg beer garden and rooftop bar is a chill, no-pretense neighborhood spot that has been a local favorite for years. The rooftop has solid Manhattan skyline views without the velvet-rope nonsense, and the beer selection leans European with German and Belgian brews. Show up in a T-shirt, grab a cold one, and watch the sun set over the city.",dishes:["Draft Beer Selection","Bratwurst","Bavarian Pretzel"]},

  // BATCH 4
  {id:1652,description:"Brooklyn mega-venue complex that turned an industrial wasteland into the city most ambitious outdoor and indoor event space. The Great Hall and Kings Hall host world-class DJs and live acts with production values that rival European festivals. If you are into electronic music and do not mind the trek to East Williamsburg, this is where the magic happens.",neighborhood:"East Williamsburg",dishes:["Great Hall Events","Kings Hall Shows","Brooklyn Mirage Summer Series"]},
  {id:1678,description:"Perched atop the tallest building in the Western Hemisphere, this observation deck delivers genuinely jaw-dropping 360-degree views from the 100th, 101st, and 102nd floors. The SkyPod elevators alone are worth the price of admission with their immersive time-lapse video walls. Even jaded New Yorkers get a little breathless up here.",instagram:"oneworldnyc",dishes:["Sunset Visit","Sky Portal Glass Floor","ONE Dine Restaurant"]},
  {id:1685,description:"The greatest free ride in New York City -- a 25-minute cruise past the Statue of Liberty and Ellis Island with Manhattan skyline views that would cost $50 on any tour boat. Grab the right-side seats heading to Staten Island for the best Liberty views. The vibe is a hilarious mix of commuters, tourists, and people just riding for the views and the onboard beer.",website:"https://www.siferry.com",dishes:["Statue of Liberty Views","Manhattan Skyline at Sunset","Onboard Snack Bar"]},
  {id:1691,description:"A rooftop escape in the heart of SoHo that channels Old Havana with tropical cocktails, Latin beats, and a scene that gets progressively livelier as the night goes on. The mojitos are legit and the Cuban-inspired bites are solid enough to soak them up. The kind of place where you go for one drink and suddenly it is midnight.",instagram:"zonadecuba",website:"https://www.zonadecuba.com",dishes:["Classic Mojito","Cuban Sandwich","Ropa Vieja"]},
  {id:1692,description:"A neighborhood rooftop bar on the Upper West Side that gives you solid pub grub with surprisingly good views without the Midtown markup. Where the UWS locals go when they want burgers and beers with a breeze and do not feel like dealing with the madness downtown. Unpretentious, reliable, and a legit neighborhood gem.",instagram:"theheightsbargrill",website:"https://www.theheightsnyc.com",dishes:["Heights Burger","Wings","Nachos"]},
  {id:1706,description:"Forget the subway -- NYC Ferry lets you cruise between Manhattan, Brooklyn, Queens, and the Bronx on the water for the price of a MetroCard swipe. The outdoor decks offer unbeatable skyline views, and routes like the Soundview and South Brooklyn lines are practically scenic tours. One of the most underrated ways to experience the city.",dishes:["East River Skyline Views","Sunset Rides","Onboard Bar"]},
  {id:1707,description:"A glass-enclosed luxury dinner cruise that floats you around Manhattan with surprisingly competent prix-fixe dining and live music. Unabashedly romantic and touristy, but the all-glass vessel means the views are spectacular from every seat. Perfect for anniversaries, proposals, or impressing out-of-towners who want that cinematic NYC experience.",dishes:["Prix-Fixe Dinner Cruise","Brunch Cruise","Sunset Sailing"]},
  {id:1719,description:"The undisputed king of Arthur Avenue, the Bronx real Little Italy that makes Manhattan tourist-trap version look embarrassing. The Migliucci family has been slinging heroic Italian sandwiches and imported goods for decades. The combo heroes are piled absurdly high with top-tier imported meats and cheeses -- this is destination-worthy eating.",instagram:"mikesdeliarthurave",neighborhood:"Bronx",dishes:["Italian Combo Hero","Fresh Mozzarella","Pasta of the Day"]},
  {id:1728,description:"A New York Jewish deli institution that survived a move from its original Second Avenue location and came back stronger than ever. The pastrami is hand-carved, piled sky-high, and absolutely competes with Katz for the best in the city -- without the insane tourist lines. The chopped liver is arguably the gold standard.",dishes:["Pastrami Sandwich","Matzo Ball Soup","Chopped Liver"]},
  {id:1737,description:"A refined West Village steakhouse that combines classic chophouse vibes with a modern sensibility and genuinely excellent dry-aged beef. The room is dark, handsome, and exactly what you want from a New York steakhouse without the corporate expense-account stuffiness. A serious neighborhood contender in a city drowning in steak options.",instagram:"theeightysix",dishes:["Dry-Aged Ribeye","Bone Marrow","Creamed Spinach"]},
  {id:1739,description:"A buzzy West Village newcomer serving creative New American plates in an intimate, moody setting that feels like a dinner party at your coolest friend apartment. The seasonal menu changes frequently, but everything is thoughtfully composed with bold flavors and beautiful plating. The wine list is genuinely interesting.",dishes:["Seasonal Tasting Plates","Handmade Pasta","Natural Wine Pairings"]},
  {id:1740,description:"A gorgeous SoHo Mediterranean spot that treats seasonal vegetables and Middle Eastern flavors with fine-dining finesse. The wood-fired dishes are the stars, and the hummus alone is worth the trip -- silky, warm, and absolutely perfect. The whole roasted cauliflower is one of the most Instagrammed dishes in the neighborhood.",instagram:"oreshrestaurant",dishes:["Wood-Fired Hummus","Whole Roasted Cauliflower","Lamb Shoulder"]},
  {id:1743,description:"A sultry Lower East Side gem where French bistro classics collide with Vietnamese flavors in ways that feel completely natural and deeply delicious. The pho French onion soup is the kind of genius mashup that makes you wonder why nobody did it sooner. The room is intimate and atmospheric, and the cocktail program punches well above its weight.",dishes:["Pho French Onion Soup","Bo Luc Lac","Vietnamese Coffee Creme Brulee"]},
  {id:1786,description:"Midtown premier Korean BBQ destination where you grill premium meats over real charcoal at your table, giving everything that unmistakable smoky depth. Open until the wee hours, it has become the go-to for post-work K-BBQ sessions and late-night meat feasts. The banchan spread is generous and the galbi is absolutely top-tier.",dishes:["Prime Galbi","Beef Brisket","Haemul Pajeon"]},
  {id:1799,description:"The legendary Nolita spot from Rich Torrisi and Mario Carbone that launched the Major Food Group empire. Known for Italian-American sandwiches and dishes elevated to fine-art status with house-roasted meats and perfect bread. The chicken parm hero is absurdly good -- crispy cutlet, tangy sauce, melted mozz on fresh bread.",dishes:["Italian Combo Sandwich","Chicken Parm","Turkey Hero"]},
  {id:1002,description:"Daniel Humm legendary Flatiron tasting-menu temple that went fully plant-based in 2021 and somehow maintained its status as one of the most extraordinary dining experiences on the planet. Love it or hate it, the multi-course vegan tasting menu is technically dazzling and theatrically unforgettable. Three Michelin stars and a price tag that will make your eyes water.",dishes:["Multi-Course Plant-Based Tasting","Sunflower Butter Course","Seasonal Vegetable Compositions"]},
  {id:1017,description:"The absolute best tacos in Manhattan, served from a no-frills counter inside Chelsea Market that consistently has a line out the door -- and it is worth every minute. The adobada on a freshly pressed corn tortilla is a near-religious experience. Three tacos and a horchata for under $15 is the best lunch deal in the neighborhood, period.",dishes:["Adobada Taco","Carne Asada Taco","Nopal Taco"]},
  {id:1020,description:"Daniel Rose swoon-worthy French restaurant in SoHo that made classic French cooking feel exciting again when everyone else was chasing trends. The room is drop-dead gorgeous -- soaring ceilings, Parisian elegance -- and the food is refined without being fussy. The roast chicken is impossibly perfect, and the souffle is a showstopper.",dishes:["Roast Chicken for Two","Grand Marnier Souffle","Quenelle de Brochet"]},
  {id:1040,description:"Daniel Boulud stunning Midtown East restaurant inside One Vanderbilt that proves fine dining and sustainability can coexist beautifully. The soaring glass-and-greenery-filled space is one of the most gorgeous dining rooms in New York, and the vegetable-forward French-Mediterranean menu lets pristine seafood shine. Two Michelin stars and worth every penny.",dishes:["Dover Sole","Seasonal Vegetable Tasting","Lobster Thermidor"]},
  {id:1058,description:"The hand-pulled noodle empire that started as a tiny Flushing basement stall and conquered New York City one spicy, cumin-laced bowl at a time. The liang pi cold noodles are addictive, and the spicy cumin lamb hand-ripped noodles are a legitimate must-eat NYC dish. Fast, cheap, fiery, and absolutely essential -- this is the people champion of New York noodles.",instagram:"xianfoods",dishes:["Spicy Cumin Lamb Noodles","Liang Pi Cold Skin Noodles","Lamb Burger"]},
  {id:1077,description:"Hidden above Gage and Tollner in Brooklyn Heights, this serious tiki bar treats the genre with a reverence and creativity that most tiki spots only dream about. The cocktails are meticulously researched, often pulling from obscure vintage recipes, and the presentation is impeccable without being gimmicky. Dark, moody, and a genuine escape from the outside world.",instagram:"sunkenharbor",website:"https://www.sunkenharborclub.com",dishes:["Navy Grog","Jet Pilot","Seasonal Tiki Cocktails"]},
  {id:1093,description:"Missy Robbins Williamsburg pasta palace where every single noodle is made in-house and treated with the respect it deserves. The cacio e pepe is transcendent, the mafaldini with pink peppercorn and fennel sausage is unforgettable, and the focaccia with whipped ricotta should be illegal. A waterfront space and pasta this good -- a Williamsburg essential.",dishes:["Mafaldini","Cacio e Pepe","Focaccia with Whipped Ricotta"]},
  {id:1113,description:"Jenny Kwak Park Slope Korean restaurant named after the legendary women divers of Jeju Island, and the cooking here is just as fierce and fearless. Korean food filtered through a Brooklyn lens -- creative, seasonal, and deeply personal without ever feeling gimmicky. The tteokbokki is a must, and the fried chicken sandwich at brunch has a cult following.",dishes:["Tteokbokki","Fried Chicken Sandwich","Kimchi Fried Rice"]},
  {id:1131,description:"The seafood-focused sibling of Los Tacos No. 1 inside Chelsea Market, serving Baja-style fish tacos and ceviches that transport you straight to a Mexican beach town. The shrimp tostada is piled high with perfectly seasoned seafood, and the fish taco with crispy battered fish and creamy chipotle sauce is a thing of beauty. Same no-frills counter energy, same insane quality.",instagram:"losmariscos1",dishes:["Baja Fish Taco","Shrimp Tostada","Ceviche"]},
  {id:1133,description:"A drop-dead gorgeous Williamsburg oyster bar that channels a New Orleans absinthe house with a lush garden, impeccable cocktails, and one of the best raw bars in the city. Happy hour here is legendary -- dollar oysters that are actually good quality, not sad little afterthoughts. The absinthe program is world-class and the back garden is pure magic.",dishes:["Oysters on the Half Shell","Seafood Tower","Absinthe Drip"]},
  {id:1135,description:"A tiny Chinatown gem serving lovingly made Malaysian comfort food that is nearly impossible to find done this well in NYC. Kyo Pang menu reads like a greatest hits of Malaysian hawker stalls -- nasi lemak, laksa, and some of the best kaya toast outside of Kuala Lumpur. The waits can be real, but every bite justifies the patience.",dishes:["Nasi Lemak","Laksa","Kaya Toast with Soft-Boiled Eggs"]},
  {id:1136,description:"Anthony Mangieri legendary pizza temple on the Lower East Side where each pie is a masterclass in simplicity and obsessive craftsmanship. He makes a limited number of pizzas each day with meticulously sourced ingredients and a dough fermentation process that borders on spiritual practice. The Margherita is regularly cited as one of the best pizzas in America.",dishes:["Margherita","Marinara","Filetti"]},
  {id:1137,description:"The Upper West Side beloved Southern comfort food destination where biscuits are the size of your head and everything comes with a pickle on the side. Indulgent, unapologetic, and perfect for hangovers, cold weather, and anyone who believes in the healing power of biscuits and gravy. The brunch lines are legendary for good reason.",dishes:["Buttermilk Biscuits with Gravy","Fried Chicken and Pickles","Mac and Cheese"]},
  {id:1140,description:"Michael White refined Italian-French restaurant tucked inside the Langham Hotel in Midtown, serving elegant pastas and proteins that showcase his signature Riviera-inspired cooking. The tasting menus are beautifully composed, and the lobster is a perennial standout. A one-Michelin-star haven of calm in the chaos of Midtown.",dishes:["Lobster Brodetto","Handmade Tajarin Pasta","Tasting Menu"]},
  {id:1141,description:"Michael White crown jewel on Central Park South, where Italian coastal cuisine meets New York luxury in one of the most polished dining rooms in the city. The fusilli with octopus and bone marrow is one of NYC most iconic pasta dishes -- rich, briny, and absolutely unforgettable. Two Michelin stars and a power-lunch scene that rivals any in Midtown.",neighborhood:"Central Park South",dishes:["Fusilli with Octopus and Bone Marrow","Crudo Misto","Branzino"]},
  {id:1142,description:"A Detroit-style pizza operation in Midtown slinging thick, crispy-edged, cheese-crusted squares that are ridiculously satisfying. The signature move is that caramelized cheese crown around the edges of the pan -- crunchy, golden, and worth every carb. A quick-serve operation that punches way above its weight class for a Midtown lunch spot.",dishes:["Detroit-Style Pepperoni","Classic Cheese Square","Pepperoni with Hot Honey"]},
];

// Spots to REMOVE (permanently closed)
const removeIds = new Set([1361, 1120, 1165]); // Govinda's, Morgenstern's, Dhamaka Kitchen (duplicate)

let updated = 0;
let removed = 0;

// Apply fixes
fixes.forEach(fix => {
  const spot = arr.find(r => r.id === fix.id);
  if(!spot) { console.log('  NOT FOUND:', fix.id); return; }
  if(fix.description) spot.description = fix.description;
  if(fix.instagram !== undefined) spot.instagram = fix.instagram;
  if(fix.website !== undefined) spot.website = fix.website;
  if(fix.dishes) spot.dishes = fix.dishes;
  if(fix.neighborhood) spot.neighborhood = fix.neighborhood;
  updated++;
});

// Remove closed spots
const before = arr.length;
const filtered = arr.filter(r => !removeIds.has(r.id));
removed = before - filtered.length;

console.log('Updated', updated, 'spots');
console.log('Removed', removed, 'closed spots (Govinda\'s, Morgenstern\'s, Dhamaka Kitchen)');
console.log('New total:', filtered.length);

// Write back
html = html.substring(0, arrStart) + JSON.stringify(filtered) + html.substring(arrEnd);
fs.writeFileSync('index.html', html, 'utf8');
fs.copyFileSync('index.html', 'index');
console.log('Done!');
